export default function collectText(node) {
  if (!node) return '';

  if (node.nodeType === 3) {
    return node.nodeValue == null ? '' : String(node.nodeValue);
  }

  const children = Array.isArray(node.childNodes) ? node.childNodes : [];
  let out = '';
  for (const child of children) {
    out += collectText(child);
  }
  return out;
}

