export default function collectText(node) {
  if (!node) return '';

  let out = '';
  const stack = [node];

  while (stack.length) {
    const cur = stack.pop();
    if (!cur) continue;

    if (cur.nodeType === 3) {
      if (cur.nodeValue != null) out += String(cur.nodeValue);
      continue;
    }

    const children = Array.isArray(cur.childNodes) ? cur.childNodes : [];
    // push right-to-left so we process left-to-right
    for (let i = children.length - 1; i >= 0; i--) {
      stack.push(children[i]);
    }
  }

  return out;
}
